import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Account","description":"","frontmatter":{},"headers":[],"relativePath":"app/account.md","filePath":"app/account.md"}'),r={name:"app/account.md"};function n(i,e,l,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="account" tabindex="-1">Account <a class="header-anchor" href="#account" aria-label="Permalink to &quot;Account&quot;">​</a></h1><p>Your account settings hold your personal details, sign-in credentials and the SSH keys Tragwerk uses for git access. Open them from the user menu in the topbar, or go to <strong>Account settings</strong> directly. Everything lives on a single page, split into Profile, Change password, SSH keys and Two-factor authentication sections.</p><h2 id="update-your-profile" tabindex="-1">Update your profile <a class="header-anchor" href="#update-your-profile" aria-label="Permalink to &quot;Update your profile&quot;">​</a></h2><p>The Profile card shows your avatar, full name and current email address.</p><ol><li>Open <strong>Account settings</strong>.</li><li>Edit <strong>First name</strong>, <strong>Last name</strong> and/or <strong>Email address</strong>.</li><li>Click <strong>Save profile</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title">Email changes need confirmation</p><p>Changing your email address does not take effect immediately. Tragwerk sends a confirmation link to the <strong>new</strong> address; the change is applied only after you click it. Until then your existing address stays active.</p></div><h2 id="change-your-password" tabindex="-1">Change your password <a class="header-anchor" href="#change-your-password" aria-label="Permalink to &quot;Change your password&quot;">​</a></h2><ol><li>In the <strong>Change password</strong> card, enter your <strong>Current password</strong>.</li><li>Enter a <strong>New password</strong> and repeat it in <strong>Confirm new password</strong>.</li><li>Click <strong>Update password</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use at least 8 characters; a number and a symbol are recommended. If you have lost access to your account entirely, use the password-reset link on the login page instead.</p></div><h2 id="ssh-keys" tabindex="-1">SSH keys <a class="header-anchor" href="#ssh-keys" aria-label="Permalink to &quot;SSH keys&quot;">​</a></h2><p>Tragwerk uses your SSH public keys for <strong>git access</strong> — for example to pull from or push to repositories that authenticate over SSH. Keys are listed by name and the date they were added.</p><h3 id="add-a-key" tabindex="-1">Add a key <a class="header-anchor" href="#add-a-key" aria-label="Permalink to &quot;Add a key&quot;">​</a></h3><ol><li><p>In the <strong>SSH Keys</strong> card, fill in a <strong>Name</strong> to recognise the key later (e.g. <code>laptop</code> or <code>ci-runner</code>).</p></li><li><p>Paste the <strong>public key</strong> — the full single line, starting with the key type:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh-ed25519 AAAAC3NzaC1lZDI1NTE5AAAAI... you@host</span></span></code></pre></div></li><li><p>Click <strong>Add key</strong>.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">Public key only</p><p>Paste the contents of your <code>.pub</code> file (for example <code>~/.ssh/id_ed25519.pub</code>). Never paste your private key.</p></div><h3 id="delete-a-key" tabindex="-1">Delete a key <a class="header-anchor" href="#delete-a-key" aria-label="Permalink to &quot;Delete a key&quot;">​</a></h3><p>Click the trash icon next to a key and confirm in the dialog. Deletion is immediate and cannot be undone; remove keys you no longer use.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/two-factor">Two-Factor Authentication</a></li><li><a href="/app/teams">Teams &amp; Roles</a></li><li><a href="/app/projects">Projects</a></li></ul>',18)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
